// Separamos posts de comentarios (el actor con scrapeComments:true devuelve ambos).
// Posts tienen url tipo /p/<shortcode>/ o /reel/<shortcode>/.
// Comments tienen ownerUsername + text + postUrl.
const items = $input.all().map(i => i.json);
const posts = [];
const commentsByPost = {};

for (const d of items) {
  const isComment = d.text && d.postUrl && !d.shortCode;
  if (isComment) {
    const key = d.postUrl;
    if (!commentsByPost[key]) commentsByPost[key] = [];
    commentsByPost[key].push(d.text);
    continue;
  }
  posts.push(d);
}

return posts.map(d => {
  const url = d.url || (d.shortCode ? 'https://www.instagram.com/p/' + d.shortCode + '/' : '');
  // Try multiple field name variants — Apify scraper output evolved
  const likes = d.likesCount ?? d.likes_count ?? d.likeCount ?? d.likes ?? 0;
  const comments = d.commentsCount ?? d.comments_count ?? d.commentCount ?? d.numComments ?? d.comments ?? 0;
  const followers = d.ownerFollowerCount ?? d.owner?.followersCount ?? d.owner?.followers_count ?? d.owner?.edge_followed_by?.count ?? d.user?.followersCount ?? d.followersCount ?? 0;
  const views = d.videoViewCount ?? d.video_view_count ?? d.videoPlayCount ?? d.viewCount ?? 0;
  // Comments scrapeados (texto) — para análisis de sentimiento del público
  const scraped = commentsByPost[url] || (Array.isArray(d.latestComments) ? d.latestComments.map(c => c.text || c).filter(Boolean) : []);
  return {
    url,
    caption: d.caption || d.alt || '',
    hashtags: Array.isArray(d.hashtags) ? d.hashtags : [],
    timestamp: d.timestamp || d.takenAtTimestamp || '',
    likesCount: Number(likes) || 0,
    commentsCount: Number(comments) || 0,
    type: d.type || 'image',
    ownerUsername: d.ownerUsername || d.username || '',
    ownerFollowerCount: Number(followers) || 0,
    videoViewCount: Number(views) || 0,
    isSponsored: !!(d.isSponsored || d.isPinned),
    commentTexts: scraped.slice(0, 30),
    platform: 'INSTAGRAM'
  };
});

return $input.all().map(item => {
  const d = item.json;
  const text = d.text || d.message || d.story || '';
  const hashtags = (text.match(/#[\w\u00C0-\u024F]+/g) || []).map(h => h.slice(1));
  return {
    url: d.url || d.postUrl || d.link || '',
    caption: text,
    hashtags,
    timestamp: d.time || d.createdTime || d.date || '',
    likesCount: d.likes || d.likesCount || d.reactionsCount || 0,
    commentsCount: d.comments || d.commentsCount || 0,
    type: d.type || 'photo',
    ownerUsername: d.pageName || d.pageAlias || d.username || '',
    videoViewCount: d.videoViewCount || d.views || 0,
    ownerFollowerCount: d.pageFans || d.fans || d.followers || d.pageFollowers || 0,
    isSponsored: !!(d.isSponsored),
    platform: 'FACEBOOK'
  };
});

return $input.all().map(item => {
  const d = item.json;
  const text = d.text || d.desc || '';
  const hashtags = Array.isArray(d.hashtags)
    ? d.hashtags.map(h => h.name || h.title || h).filter(h => typeof h === 'string')
    : (text.match(/#[\w\u00C0-\u024F]+/g) || []).map(h => h.slice(1));
  return {
    url: d.webVideoUrl || d.videoUrl || d.shareUrl || '',
    caption: text,
    hashtags,
    timestamp: d.createTimeISO || (d.createTime ? new Date(d.createTime * 1000).toISOString() : ''),
    likesCount: d.diggCount || d.likeCount || 0,
    commentsCount: d.commentCount || 0,
    type: 'video',
    ownerUsername: (d.authorMeta && d.authorMeta.name) || d.authorUniqueId || '',
    ownerFollowerCount: (d.authorMeta && (d.authorMeta.fans || d.authorMeta.followerCount)) || 0,
    videoViewCount: d.playCount || d.viewCount || 0,
    isSponsored: false,
    platform: 'TIKTOK'
  };
});

// Build records for Supabase social_posts. Match marca por ownerUsername.
// Pilar canónico (5 únicos, sin combinaciones). Engagement se calcula en dashboard.
try {
  const raw = $input.first().json;
  const originalPosts = $('Aggregate Posts').first().json.posts || [];
  const config = $('Set Config').first().json;
  const marcas = config.brands.map(b => b.toLowerCase());
  const fromDate = config.fromDate || '2026-01-01';
  const VALID_PILARS = ['Branding','Producto','Promo','Influencer','Educacional'];

  // Extract GPT JSON
  let analysisArray;
  if (raw.choices && raw.choices[0]) {
    const content = raw.choices[0].message?.content || '';
    const parsed = JSON.parse(content);
    analysisArray = parsed.analysis || parsed;
  } else if (Array.isArray(raw)) {
    analysisArray = raw;
  } else {
    throw new Error('GPT response inesperado: ' + JSON.stringify(Object.keys(raw)));
  }
  if (!Array.isArray(analysisArray)) throw new Error('analysis no es un array');

  const analysisMap = {};
  for (const a of analysisArray) { if (a.url) analysisMap[a.url] = a; }

  // Match marca por ownerUsername (normalizado)
  const norm = s => (s || '').toLowerCase().replace(/[^a-z0-9]/g, '');
  const matchMarca = (owner) => {
    const o = norm(owner);
    if (!o) return null;
    return marcas.find(m => {
      const mn = norm(m);
      return mn && (o === mn || o.startsWith(mn) || mn.startsWith(o));
    }) || null;
  };

  // Pilar guard
  const pickPilar = (raw) => {
    if (!raw) return 'Branding';
    if (VALID_PILARS.includes(raw)) return raw;
    // Si vino combinado tipo "Producto/Branding", agarrá el primero válido
    const parts = raw.split('/').map(s => s.trim());
    for (const p of parts) if (VALID_PILARS.includes(p)) return p;
    return 'Branding';
  };

  const results = [];
  for (const post of originalPosts) {
    try {
      const url = post.url || '';
      if (!url) continue;
      const analysis = analysisMap[url];
      if (!analysis) continue;

      const fecha = post.timestamp ? new Date(post.timestamp).toISOString().slice(0, 10) : null;
      if (!fecha || fecha < fromDate) continue;

      const marca = matchMarca(post.ownerUsername || post.username || '');
      if (!marca) continue;

      const likes = Number(post.likesCount) || 0;
      const comments = Number(post.commentsCount) || 0;
      const views = Number(post.videoViewCount) || 0;
      const followers = Number(post.ownerFollowerCount) || 0;

      const t = (post.type || '').toLowerCase();
      const contentType = post.platform === 'TIKTOK' ? 'VIDEO'
        : t.includes('video') || t.includes('reel') ? 'VIDEO'
        : t.includes('sidecar') || t.includes('album') ? 'SIDECAR' : 'IMAGE';

      const sent = analysis.sentimiento;
      const hasSent = sent && typeof sent === 'object' && (sent.positivo != null || sent.negativo != null || sent.neutro != null);
      results.push({
        red_social:   post.platform,
        url,
        pilar:        pickPilar(analysis.pilar),
        positivo:     hasSent ? (Number(sent.positivo) || 0) : null,
        negativo:     hasSent ? (Number(sent.negativo) || 0) : null,
        neutro:       hasSent ? (Number(sent.neutro)   || 0) : null,
        likes,
        comentarios:  comments,
        engagement:   followers > 0 ? Number((((likes + comments) / followers) * 100).toFixed(3)) : null,
        fecha,
        tipo:         post.isSponsored ? 'PAUTA' : 'ORGÁNICO',
        marca,
        views,
        content_type: contentType,
        followers
      });
    } catch (e) { /* skip */ }
  }

  return results.map(json => ({ json }));
} catch (e) {
  return [{ json: { error: e.message } }];
}
